	if !allowedSearchColumns[searchColumn] {
		w.WriteHeader(http.StatusBadRequest)
		json.NewEncoder(w).Encode(ErrorResponse{Error: fmt.Sprintf("invalid search_column: must be one of: username, email")})
		return
	}

	sortBy := r.URL.Query().Get("sort_by")
